<template><div class="app-container"><section class="capability-brief"><div><p class="eyebrow">Learning Resource Tools</p><h2>Resource Reading</h2><p>Read textbooks, course materials, and academic papers. Convert reading progress into quizzable study materials.</p></div><div class="brief-actions"><input v-if="!documentUploaded" id="top-file-input" type="file" accept=".pdf,.doc,.docx,.txt,.md" @change="handleFileChange" class="top-upload-input" title="Upload"><button @click="goPage('/app/full-chain')">Back</button><button @click="goPage('/app/dashboard')">Profile</button><button @click="goPage('/app/ai-media?tab=ppt')">PPT</button></div></section><section v-if="!documentUploaded" class="textbook-studio"><div class="textbook-studio__header"><h3>Textbook Library</h3><p>Select textbooks by learning direction for long-term reading memory</p></div><div class="major-tabs"><button v-for="m in ['AI Basics','Python','ML','CS','Mechanical']" :key="m" @click="activeMajor=m" :class="{active:activeMajor===m}">{{m}}</button></div><div v-if="selectedBook" class="reader-main"><h3>{{selectedBook.title}}</h3><a :href="selectedBook.url" target="_blank">Open Textbook</a><div v-if="selectedChapter" class="reading-workbench"><h4>{{selectedChapter.title}}</h4><label>Page: {{readingPage}}/{{selectedChapter.pages}}<input type="range" :min="1" :max="selectedChapter.pages" v-model.number="readingPage"></label><button @click="saveCurrentProgress">Save Progress</button></div></div></section><div v-if="!documentUploaded" class="upload-screen"><div class="upload-area"><h2>Upload Document</h2><span>Supports pdf, doc, docx, txt, md. Max 20MB</span><div class="custom-upload"><label class="upload-drop-zone" for="top-file-input" style="cursor:pointer">Click or drag file here</label><label class="primary-upload-btn" for="top-file-input" style="cursor:pointer;display:inline-flex;align-items:center">Upload File</label></div></div></div><div v-if="documentUploaded" class="chat-screen"><div class="document-header"><h2>{{currentSession?.name}}</h2><div class="doc-header-actions"><button @click="goBackToUpload">Back</button><button @click="summarizeCurrentDocument">Analyze</button></div></div><div class="document-content"><pre>{{fileContent}}</pre></div></div></div></template><script>import axios from 'axios';import DOMPurify from 'dompurify';import {getCurrentUser} from '@/utils/learningPersonalization';export default{name:'ExerciseChange',data(){return{documentUploaded:false,isUploading:false,uploadError:null,fileContent:'',localFile:null,currentSession:null,chatSessions:[],activeChat:0,searchQuery:'',activeMajor:'AI Basics',readingPage:1,selectedBook:null,selectedChapter:null,currentUser:{}}},created(){this.currentUser=getCurrentUser()},methods:{sanitizeHtml(h){return h?DOMPurify.sanitize(h,{ALLOWED_TAGS:['p','br','strong','em','h1','h2','h3','h4','table','tr','td','th','ul','ol','li','span','div','pre','code'],ALLOWED_ATTR:['src','alt','class','style']}):''},goPage(p){this.$router.push(p)},goBackToUpload(){this.documentUploaded=false;this.currentSession=null;this.fileContent=''},handleFileChange(e){const f=e.target.files[0];if(!f)return;this.localFile=f;this.isUploading=true;const r=new FileReader();r.onload=()=>{this.fileContent=r.result;this.documentUploaded=true;this.currentSession={name:f.name,date:new Date().toLocaleDateString(),fileId:null,localFile:f};this.isUploading=false;this.uploadToBackend(f)};r.readAsText(f)},async uploadToBackend(f){try{const fd=new FormData();fd.append('file',f);const r=await axios.post('/api/document/upload',fd);if(r.data?.success&&this.currentSession){this.currentSession.fileId=r.data.fileId;this.addMessage('system','Uploaded. Generating summary...')}}catch(e){this.addMessage('system','Upload failed: '+e.message)}},async summarizeCurrentDocument(){if(!this.currentSession?.fileId)return;this.addMessage('system','Analyzing...');try{const r=await axios.post('/api/document/summary/from-text',{fileId:this.currentSession.fileId,content:this.fileContent||''});const s=(r.data&&r.data.summary)||'';if(s)this.addMessage('ai','Analysis: '+s)}catch(e){this.addMessage('system','Analysis failed')}},addMessage(role,text){}}}</script>